export default function myBind(fn, thisArg, ...boundArgs) {
  if (typeof fn !== 'function') {
    throw new TypeError('myBind: fn must be a function');
  }

  function boundFn(...callArgs) {
    const isConstructorCall = this instanceof boundFn;
    const thisToUse = isConstructorCall ? this : thisArg;
    return fn.apply(thisToUse, [...boundArgs, ...callArgs]);
  }

  // Preserve prototype chain so `new boundFn()` instances are also `instanceof fn`.
  if (fn.prototype) {
    boundFn.prototype = Object.create(fn.prototype);
    // (Optional) keep constructor reference tidy
    Object.defineProperty(boundFn.prototype, 'constructor', {
      value: boundFn,
      writable: true,
      configurable: true
    });
  }

  return boundFn;
}
